import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';

function InventoryPage() {
  const [books, setBooks] = useState([]);
  const [error, setError] = useState('');
  const navigate = useNavigate();

  useEffect(() => {
    const fetchBooks = async () => {
      try {
        const userInfo = JSON.parse(localStorage.getItem('userInfo'));
        const config = {
          headers: {
            Authorization: `Bearer ${userInfo.token}`,
          },
        };
        const { data } = await axios.get('/api/books', config);
        setBooks(data);
      } catch (err) {
        setError(err.response?.data?.message || 'Could not fetch books');
      }
    };

    fetchBooks();
  }, []);

  const formatDate = (dateString) => {
    if (!dateString) return 'N/A';
    return new Date(dateString).toLocaleDateString();
  };

  return (
    <EmployeeLayout title="Dashboard">
      {error && <p className={styles.error}>{error}</p>}
      <div>
        <h1>Inventory Management</h1>
        {error && <p style={{ color: 'red' }}>{error}</p>}
        <table style={{ width: '100%', borderCollapse: 'collapse' }}>
          <thead>
            <tr>
              <th>Series Title</th>
              <th>Issue #</th>
              <th>Publisher</th>
              <th>Release Date</th>
              <th>Total Pulls</th>
              <th>Tags</th>
              <th>Actions</th>
            </tr>
          </thead>
          <tbody>
            {books.map((book) => (
              <tr key={book._id}>
                <td>{book.seriesTitle}</td>
                <td>{book.issueNumber}</td>
                <td>{book.publisher}</td>
                <td>{formatDate(book.releaseDate)}</td>
                <td>{book.pullCount}</td>
                <td>{book.tags.join(', ')}</td>
                <td>
                  <button onClick={() => navigate(`/editbook/${book._id}`)}>
                    Edit
                  </button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
        <style>{`
          th, td {
            border: 1px solid #ddd;
            padding: 8px;
            text-align: left;
          }
        `}</style>
      </div>
    </EmployeeLayout>  );
}

export default InventoryPage;
